+#[test]
+fn btrfs_leaf_fixture_conforms() {
+    let (header, items) = validate_btrfs_leaf_fixture(&fixture_path("btrfs_leaf_node.json"))
+        .expect("btrfs leaf fixture");
+    assert_eq!(header.level, 0, "should be a leaf");
