+    // Items should be sorted by key (objectid then type)
+    for pair in items.windows(2) {
+        let a = &pair[0].key;
+        let b = &pair[1].key;
+        assert!(
+            (a.objectid, a.item_type) <= (b.objectid, b.item_type),
+            "items should be sorted by key"
+        );
+    }
+}
